-- Dumping data for table `books`
--

LOCK TABLES `books` WRITE;
/*!40000 ALTER TABLE `books` DISABLE KEYS */;
INSERT INTO `books` VALUES ('02c4ef5e-5097-43c4-ad7c-a302be6bc108','1984','George Orwell',146001,'PHYSICAL','1984 adalah buku karya George Orwell yang sangat populer.','8425d51a-0527-4b93-85e5-2e8588563e93','PUBLISHED','88843b74-9a8d-4e54-af65-1ea37f282fcb',1,'2026-02-14 02:29:06','2026-02-21 14:37:48',16,0),('03a8f07f-ea0a-4143-afcb-960dc36fc36a','Shoe Dog','Phil Knight',160841,'PHYSICAL','Shoe Dog adalah buku karya Phil Knight yang sangat populer. Lorem ipsum dolor sit amet consectetur adipisicing elit. Cumque modi excepturi veniam, totam ab tempora laudantium magnam odio debitis similique itaque repellendus possimus odit obcaecati neque aliquam voluptas ipsam! Impedit. Lorem ipsum dolor sit amet consectetur, adipisicing elit. Voluptate ducimus earum nobis. Consequatur, culpa. Atque molestias cupiditate praesentium, aspernatur consectetur necessitatibus sint officia perspiciatis, nihil quidem vitae distinctio beatae. Illum! Lorem ipsum dolor sit, amet consectetur adipisicing elit. Ea similique quae recusandae error ducimus autem, perferendis voluptas earum qui mollitia dolorum sunt nihil totam. Veniam facere totam maiores fugit illo! Lorem ipsum dolor, sit amet consectetur adipisicing elit. Quia quo vero ex? Pariatur inventore nam quas cum quis laborum perspiciatis ab unde accusantium, eaque esse vero reiciendis tempore nisi eos! Lorem ipsum dolor sit amet consectetur adipisicing elit. Itaque, quisquam ex deserunt ut vitae temporibus illo a quasi. Reprehenderit ducimus delectus aspernatur esse consequuntur dolorum unde voluptatibus earum sequi distinctio! Lorem ipsum dolor sit amet consectetur adipisicing elit. Earum tempore placeat, praesentium, odio quia asperiores accusantium illo culpa a modi voluptas, ab maxime. Libero labore ex nostrum dolore, excepturi suscipit! Lorem, ipsum dolor sit amet consectetur adipisicing elit. Beatae repudiandae molestias quisquam dignissimos nostrum, doloribus amet magni iusto et incidunt voluptatibus, quaerat possimus earum accusantium deleniti pariatur voluptates inventore fugiat. Lorem ipsum dolor sit, amet consectetur adipisicing elit. Autem distinctio optio odio consectetur corporis numquam voluptatem commodi aut sit modi quas dolorum, dolore molestiae! At officia quaerat molestias earum laboriosam?','8425d51a-0527-4b93-85e5-2e8588563e93','PUBLISHED','88843b74-9a8d-4e54-af65-1ea37f282fcb',0,'2026-02-14 02:45:56','2026-02-14 02:45:56',33,0),('04a717ed-b39f-476e-b751-b52eb5a7c7a8','The Strange House','Uketsu, Kyo Ayano',55000,'Comic','<p><span style=\"color: rgb(113, 121, 127);\">Saat melihat denah rumah itu, aku membatin, sungguh rumah yang aneh.” “Aku” berprofesi sebagai penulis lepas spesialis okultisme. Suatu hari, kenalanku memperlihatkan denah sebuah rumah yang memiliki sebuah \"ruang misterius\" yang tidak jelas wujudnya. Begitu aku menanyakan pendapat Pak Kurihara, seorang arsitek, mulai terlihat berbagai kejanggalan di rumah itu.</span></p><p><br></p><p><span style=\"color: rgb(113, 121, 127);\">Selling Point:</span></p><p><span style=\"color: rgb(113, 121, 127);\">- Diangkat dari novel laris \"Hen na Ie\" yang juga telah terbit di Indonesia dengan judul \"Teka-Teki Rumah Aneh\".</span></p><p><span style=\"color: rgb(113, 121, 127);\">- Novelnya telah diangkat menjadi film bioskop di Jepang pada tahun 2024.</span></p><p><span style=\"color: rgb(113, 121, 127);\">- Salah satu pemenang \"Minna ga Erabu!! Denshi Comic Taishō 2024\" kategori Men\'s Comic.</span></p><p><br></p><p><span style=\"color: rgb(113, 121, 127);\">Informasi Tambahan:</span></p><p><span style=\"color: rgb(113, 121, 127);\">#teka teki rumah aneh #hen na ie #uketsu #kyo ayano #misteri #thriller</span></p><p><br></p><p><br></p><p><span style=\"color: rgb(113, 121, 127);\">*****</span></p><p><span style=\"color: rgb(113, 121, 127);\">Di antara jenis buku lainnya, komik memang disukai oleh semua kalangan mulai dari anak kecil hingga orang dewasa. Alasan komik lebih disukai oleh banyak orang karena disajikan dengan penuh dengan gambar dan cerita yang mengasyikan sehingga mampu menghilangkan rasa bosan di kala waktu senggang.</span></p><p><br></p><p><span style=\"color: rgb(113, 121, 127);\">Komik seringkali dijadikan sebagai koleksi dan diburu oleh penggemarnya karena serinya yang cukup terkenal dan kepopulerannya terus berlanjut sampai saat ini. Dalam memilih jenis komik, ada baiknya perhatikan terlebih dahulu ringkasan cerita komik di sampul bagian belakang sehingga sesuai dengan preferensi pribadi pembaca.</span></p><p><br></p>','20cb820e-c6a6-4b99-94e4-463a6cc30087','PUBLISHED','a758e486-49ef-482c-b5d2-95ae78c12eba',1,'2026-01-29 08:43:13','2026-02-19 08:44:09',4,1),('05629dd4-c33b-4e5c-ada2-f969340a4565','The Pragmatic Programmer','Andrew Hunt',202434,'PHYSICAL','The Pragmatic Programmer adalah buku karya Andrew Hunt yang sangat populer.','8425d51a-0527-4b93-85e5-2e8588563e93','PUBLISHED','8b3f6507-a979-4b9b-8acc-ade072eb2dd5',0,'2026-02-14 02:29:06','2026-02-16 08:22:59',10,0),('08154433-9ce9-49ef-8904-8a2fdfc672d7','Don\'t Make Me Think','Steve Krug',102509,'PHYSICAL','Don\'t Make Me Think adalah buku karya Steve Krug yang sangat populer. Lorem ipsum dolor sit amet consectetur adipisicing elit. Cumque modi excepturi veniam, totam ab tempora laudantium magnam odio debitis similique itaque repellendus possimus odit obcaecati neque aliquam voluptas ipsam! Impedit. Lorem ipsum dolor sit amet consectetur, adipisicing elit. Voluptate ducimus earum nobis. Consequatur, culpa. Atque molestias cupiditate praesentium, aspernatur consectetur necessitatibus sint officia perspiciatis, nihil quidem vitae distinctio beatae. Illum! Lorem ipsum dolor sit, amet consectetur adipisicing elit. Ea similique quae recusandae error ducimus autem, perferendis voluptas earum qui mollitia dolorum sunt nihil totam. Veniam facere totam maiores fugit illo! Lorem ipsum dolor, sit amet consectetur adipisicing elit. Quia quo vero ex? Pariatur inventore nam quas cum quis laborum perspiciatis ab unde accusa