INSERT INTO `genre` VALUES ('00656d33-8696-4327-949f-d8e985cbef92','test','PUBLISHED','dasdadasd','20cb820e-c6a6-4b99-94e4-463a6cc30087','2025-08-12 07:29:08','2026-03-04 15:11:18'),('025186e6-c759-4acd-990e-41b6ddb70037','Mecha','PUBLISHED','Mecha','20cb820e-c6a6-4b99-94e4-463a6cc30087','2026-01-12 06:52:16','2026-01-12 06:52:16'),('0dd4c96e-4054-45bc-8372-9df13918544b','Stoicism','PUBLISHED','Stoicism','20cb820e-c6a6-4b99-94e4-463a6cc30087','2026-01-12 06:42:45','2026-01-12 06:42:45'),('0fba8df4-4d60-44ce-8d19-d23aef0f022f','Sci-fi','PUBLISHED','1. Definisi dan Ruang Lingkup\nScience fiction, atau sci-fi, adalah genre fiksi spekulatif yang berfokus pada konsep-konsep ilmiah, teknologi masa depan, eksplorasi ruang angkasa, perjalanan waktu, kehidupan di planet lain, dan konsekuensi sosial atau biologis dari inovasi ilmiah. Genre ini sering menggabungkan pengetahuan ilmiah yang ada dengan imajinasi penulis untuk menciptakan dunia atau skenario yang belum terjadi, namun mungkin dapat terjadi di masa depan.\n\n2. Tema dan Topik Umum\nTema-tema yang sering muncul dalam sci-fi antara lain kecerdasan buatan, robotika, genetik, evolusi manusia, realitas virtual, dan konflik antara manusia dan makhluk asing (alien). Tak jarang pula sci-fi mengangkat pertanyaan filosofis dan etis seperti: “Apa artinya menjadi manusia?”, “Apa dampak teknologi terhadap moralitas?”, atau “Apakah kita sendirian di alam semesta?” Genre ini sering bertindak sebagai cermin yang memantulkan kekhawatiran dan harapan umat manusia terhadap perkembangan ilmu pengetahuan dan teknologi.\n\n3. Fungsi Sosial dan Budaya\nLebih dari sekadar hiburan, sci-fi sering menjadi medium untuk mengkritik atau mengeksplorasi isu sosial dan politik. Lewat metafora futuristik atau dunia alternatif, sci-fi bisa membahas rasisme, ketimpangan sosial, kolonialisme, kapitalisme, bahkan kehancuran lingkungan. Dengan demikian, genre ini memberikan ruang aman bagi penonton atau pembaca untuk memikirkan ulang realitas saat ini dalam konteks yang lebih luas dan spekulatif.\n\n4. Perkembangan Historis\nGenre ini telah berkembang sejak abad ke-19 dengan karya-karya awal seperti Frankenstein oleh Mary Shelley dan The Time Machine oleh H.G. Wells. Pada abad ke-20, sci-fi semakin populer melalui buku, film, dan serial televisi. Karya-karya seperti Dune oleh Frank Herbert, 2001: A Space Odyssey oleh Arthur C. Clarke dan Stanley Kubrick, serta Blade Runner karya Ridley Scott menjadi tonggak penting dalam perkembangan genre ini.\n\n5. Pengaruh dan Daya Tarik Global\nSci-fi memiliki daya tarik lintas budaya dan generasi karena menawarkan petualangan intelektual dan imajinatif. Banyak penemuan nyata yang terinspirasi dari ide-ide sci-fi, seperti ponsel, internet, atau konsep robotika modern. Genre ini terus berkembang seiring dengan kemajuan teknologi, dan akan selalu relevan karena manusia tidak pernah berhenti bertanya: \"Apa yang akan terjadi selanjutnya?','20cb820e-c6a6-4b99-94e4-463a6cc30087','2025-08-10 17:24:54','2025-08-12 07:12:27'),('22e76ca8-3f44-4580-a059-1c7525cfab8a','colony','PUBLISHED','asdasda','20cb820e-c6a6-4b99-94e4-463a6cc30087','2025-10-21 07:35:52','2025-10-21 07:35:52'),('33493f87-a054-486f-b4f1-523b14ee9c32','Philosopy','PUBLISHED','Philosopy','20cb820e-c6a6-4b99-94e4-463a6cc30087','2026-01-12 06:41:30','2026-01-12 06:41:30'),('348e7155-eb11-4f8d-b3ed-0454f28682e2','dasds','PUBLISHED','sdasda','5fc7a8ab-cdc3-4844-aad5-99c5ff8a4545','2025-08-12 08:12:20','2025-08-12 08:12:20'),('38d148a9-161b-4dc0-961e-9f4f8eeb9d40','Cyberpunk','PUBLISHED','Cyberpunk','20cb820e-c6a6-4b99-94e4-463a6cc30087','2026-01-12 06:41:51','2026-01-12 06:41:51'),('3b9507c7-beab-4e16-be5b-e221f09e98a6','asdas','PUBLISHED','asdasd','20cb820e-c6a6-4b99-94e4-463a6cc30087','2025-08-12 08:14:06','2025-08-12 08:14:06'),('3ba00a41-3898-414b-a433-ccdb82bfc9ef','Military','PUBLISHED','Military','20cb820e-c6a6-4b99-94e4-463a6cc30087','2026-01-12 06:48:47','2026-01-12 06:48:47'),('49337a40-e3ed-4362-a888-6aefbbeaaa6a','Biography','PUBLISHED','Biography','20cb820e-c6a6-4b99-94e4-463a6cc30087','2026-01-12 07:06:31','2026-01-12 07:06:31'),('4b96b6d7-0d6f-4aef-9b0c-a95a688267fd','Absurdism','PUBLISHED','Absurdism','20cb820e-c6a6-4b99-94e4-463a6cc30087','2026-01-12 06:42:55','2026-01-12 06:42:55'),('68248cce-f83b-40ec-a91d-d9215c73b68a','Fantasy','PUBLISHED','Fantasy Cuy seru nich 😊😊','20cb820e-c6a6-4b99-94e4-463a6cc30087','2025-08-10 17:24:54','2025-08-12 07:12:28'),('7c90e6f7-b910-4449-8f7d-bb3826d94aa9','Food & Drink','PUBLISHED','makan','20cb820e-c6a6-4b99-94e4-463a6cc30087','2026-01-12 07:06:43','2026-01-12 07:06:43'),('9446f79a-15c4-4366-9170-ed3d665e6284','gfgdf','PUBLISHED','asdasd','5fc7a8ab-cdc3-4844-aad5-99c5ff8a4545','2025-08-12 08:15:09','2025-08-12 08:15:09'),('9942dd2d-982d-4d67-b450-fa86f4af3409','Romance','PUBLISHED','Romance','20cb820e-c6a6-4b99-94e4-463a6cc30087','2026-01-12 07:05:32','2026-01-12 07:05:32'),('b749dc34-71e9-416e-a7d3-04d3e0808d95','History','PUBLISHED','history','20cb820e-c6a6-4b99-94e4-463a6cc30087','2026-01-12 06:41:21','2026-01-12 06:41:21'),('be1377f0-9ea4-46d6-8911-60f5574a37a7','Mystery','PUBLISHED','Mystery','20cb820e-c6a6-4b99-94e4-463a6cc30087','2026-01-12 07:05:21','2026-01-12 07:05:21'),('d6e7b28b-f351-42a7-b03a-610ffdc9c4c6','Horror','PUBLISHED','horror','20cb820e-c6a6-4b99-94e4-463a6cc30087','2026-01-12 07:05:13','2026-01-12 07:05:13'),('ed3a5bcd-0031-411e-a7d2-d19473953ecd','asdasd123123','PUBLISHED','asdasdasdasds','5fc7a8ab-cdc3-4844-aad5-99c5ff8a4545','2025-08-12 08:14:35','2025-08-12 08:14:35'),('f76765a2-7602-4d08-beb0-4b198c7835e8','Art & Photography','PUBLISHED','Art %adasd','20cb820e-c6a6-4b99-94e4-463a6cc30087','2026-01-12 07:06:55','2026-01-12 07:06:55'),('f87ee859-2189-47d6-8d60-6aad6c48627f','Drama','PUBLISHED','Drama','20cb820e-c6a6-4b99-94e4-463a6cc30087','2026-01-12 06:52:11','2026-01-12 06:52:11'),('fc9b35d3-f6d2-4153-88d1-35b573e0d63c','asdasd','PUBLISHED','asdasd','5fc7a8ab-cdc3-4844-aad5-99c5ff8a4545','2025-08-12 07: